INSERT INTO tanahpedia_entry (id, title, content, unique_name, created_at, updated_at) VALUES (UUID(), 'יהושע בן נון', '<p>יְהוֹשֻׁעַ בִּן נוּן, יד ימינו של&nbsp;<a href=\"%D7%9E%D7%A9%D7%94\">משה</a><sup><a href=\"#note-1\" id=\"noteref-1\">א</a></sup>&nbsp;וממשיך דרכו<sup><a href=\"#note-2\" id=\"noteref-2\">ב</a></sup>, מנהיגם של ישראל בכניסתם לארץ, נביא<sup><a href=\"#note-3\" id=\"noteref-3\">ג</a></sup>.</p>\r\n<hr>\r\n<h2></h2>\r\n<h2 style=\"color: rgb(0, 0, 0);\">שמו</h2>\r\n<h4></h4>\r\n<h4></h4>\r\n<h3>מהושע ליהושע</h3>\r\n<p>נקרא בתחילה הוֹשֵׁעַ עד ש<a href=\"משה\">משה</a>&nbsp;החליף את שמו ליְהוֹשֻׁעַ<sup><a href=\"#note-4\" id=\"noteref-4\">ד</a></sup>. ורבותינו דרשו טעמים בהוספת אות יו\"ד לשמו:</p>\r\n<p>א. כברכה מ<a href=\"%D7%9E%D7%A9%D7%94\">משה</a>, שהקב\"ה המכונה \'יה\', יושיעו מעצת עשרת המרגלים<sup><a href=\"#note-5\" id=\"noteref-5\">ה</a></sup>.<br></p>\r\n<p>ב. כנגד השכר שנטל במקום עשרת המרגלים האחרים שלא השלימו משימתם כראוי<sup><a href=\"#note-6\" id=\"noteref-6\">ו</a></sup>.</p>\r\n<p>ג. בתמורה לאות יו\"ד שנלקחה מ<a href=\"שרה\">שרה</a> אמנו<sup><a href=\"#note-7\" id=\"noteref-7\">ז</a></sup>.</p>\r\n<hr>\r\n<h2 style=\"color: rgb(0, 0, 0);\">חיבוריו</h2>\r\n<p>כתב את ספר יהושע<sup><a href=\"#note-8\" id=\"noteref-8\">ח</a></sup>.</p>\r\n<p>לפי דעה בגמרא<sup><a href=\"#note-9\" id=\"noteref-9\">ט</a></sup>&nbsp;כתב שמונה פסוקים בספר דברים.</p>\r\n<p>כמו כן חיבר את תפילת עלינו לשבח<sup><a href=\"#note-10\" id=\"noteref-10\">י</a></sup>.</p>\r\n<p><br></p>\r\n<hr>\n<h2>הערות</h2>\n<ol style=\"list-style:none;padding:0;\">\n<li id=\"note-1\"><sup>א</sup> שמות לג יא <a href=\"#noteref-1\">↩</a></li>\n<li id=\"note-2\"><sup>ב</sup> במדבר כז <a href=\"#noteref-2\">↩</a></li>\n<li id=\"note-3\"><sup>ג</sup> יהושע א א ועוד; אבן עזרא דברים יח טו;&nbsp;רלב\"ג יהושע ה יג;&nbsp;זוהר בראשית כא:; שם משמואל ויחי תרע\"ה <a href=\"#noteref-3\">↩</a></li>\n<li id=\"note-4\"><sup>ד</sup> במדבר יג טז <a href=\"#noteref-4\">↩</a></li>\n<li id=\"note-5\"><sup>ה</sup> במדבר רבה פרשה טז אות ט <a href=\"#noteref-5\">↩</a></li>\n<li id=\"note-6\"><sup>ו</sup> שם שם שם <a href=\"#noteref-6\">↩</a></li>\n<li id=\"note-7\"><sup>ז</sup> ויקרא רבה פרשה יט אות ב בסוף; סנהדרין קז. <a href=\"#noteref-7\">↩</a></li>\n<li id=\"note-8\"><sup>ח</sup> בבא בתרא יד: <a href=\"#noteref-8\">↩</a></li>\n<li id=\"note-9\"><sup>ט</sup> בבא בתרא טו. <a href=\"#noteref-9\">↩</a></li>\n<li id=\"note-10\"><sup>י</sup> תשובת רב האי גאון המובאת בשערי תשובה סימן מד.&nbsp;וכן בפירושי סידור התפילה לרוקח ([קלב] מלכיות עמודים תרנו-תרנז) <a href=\"#noteref-10\">↩</a></li>\n</ol>', 'יהושע-בן-נון', NOW(), NOW());
INSERT INTO tanahpedia_entry (id, title, content, unique_name, created_at, updated_at) VALUES (UUID(), 'עלי הכהן', '<p>עֵלִי הַכֹּהֵן, כֹּהֵן גדול, שופט.</p>\r\n<h2>ברכתו של כהן צדיק</h2>\r\n<p>בעת ששימש ככהן במשכן אשר בשילה, הגיעה להתפלל שם <a href=\"חנה\">חנה</a><sup><a href=\"#note-1\" id=\"noteref-1\">א</a></sup>. לאחר דו שיח טעון מברך<sup><a href=\"#note-2\" id=\"noteref-2\">ב</a></sup>&nbsp;אותה עלי שה\' ימלא את בקשתה לפרי בטן, ואכן לאחר כחצי שנה<sup><a href=\"#note-3\" id=\"noteref-3\">ג</a></sup>&nbsp;נולד לה בנה הבכור, <a href=\"שמואל\">שמואל</a>.</p>\r\n<h2>מסירות נפשו בשפיטת עם ישראל</h2>\r\n<p>בתיאור פטירתו של עלי כתוב: \"כִּֽי־זָקֵ֥ן הָאִ֖ישׁ... וְה֛וּא שָׁפַ֥ט אֶת־יִשְׂרָאֵ֖ל אַרְבָּעִ֥ים שָׁנָֽה׃\"<sup><a href=\"#note-4\" id=\"noteref-4\">ד</a></sup>. ר\' יצחק אברבנאל מסביר<sup><a href=\"#note-5\" id=\"noteref-5\">ה</a></sup>&nbsp;שציון זקנתו ושפיטת ישראל נסמכו בכוונה באותו פסוק, שכן עלי מסר את הנפש באותן ארבעים שנה לשפוט את ישראל כראוי וגופו נחלש מהמאמץ.</p>\r\n<h2>סדר העדיפויות של אדם קדוש</h2>\r\n<p>לאחר הקרב הגרוע נגד פלשתים מבשרים לעלי על התבוסה ועל מות בניו, חָפְנִי ופִּינְחָס. רק כאשר עלי שומע שארון הא-להים נשבה הוא נופל ומת.</p>\r\n<h2>הביקורת של הקב\"ה כלפי עלי</h2>\r\n<p>במראה נבואה, מודיע הקב\"ה לשמואל הרמתי על ענשו הצפוי של עלי הכהן. הנימוק של ה\' להחלטה הרעה הזו היא התוכחה החלושה של עלי כלפי מעשיהם השליליים של בניו, חָפְנִי ופִּינְחָס.</p>\r\n<hr>\n<h2>הערות</h2>\n<ol style=\"list-style:none;padding:0;\">\n<li id=\"note-1\"><sup>א</sup> שמואל א א ט-יב <a href=\"#noteref-1\">↩</a></li>\n<li id=\"note-2\"><sup>ב</sup> שמואל א א יז <a href=\"#noteref-2\">↩</a></li>\n<li id=\"note-3\"><sup>ג</sup> ראש השנה יא א; יבמות מב.; נדה לח: <a href=\"#noteref-3\">↩</a></li>\n<li id=\"note-4\"><sup>ד</sup> שמואל א ג יח <a href=\"#noteref-4\">↩</a></li>\n<li id=\"note-5\"><sup>ה</sup> אברבנאל שמואל א ג יח <a href=\"#noteref-5\">↩</a></li>\n</ol>', 'עלי-הכהן', NOW(), NOW());
INSERT INTO tanahpedia_entry (id, title, content, unique_name, created_at, updated_at) VALUES (UUID(), 'שמשון', '<p>שופט, נזיר מבטן.</p>\r\n<hr>\r\n<h2></h2>\r\n<h2 style=\"color: rgb(0, 0, 0);\">שמו</h2>\r\n<h4></h4>\r\n<h4></h4>\r\n<h3>שֶׁמֶשׁ וּמָגֵן</h3>\r\n<p>על פי דברי ר\' יוחנן בגמרא<sup><a href=\"#note-1\" id=\"noteref-1\">א</a></sup>&nbsp;נקרא כך משום תכונתו להיות מָגֵן לעם ישראל כמו רבונו של עולם.</p>\r\n<h3>שַׁמָּשׁ</h3>\r\n<p>ר\' יצחק&nbsp;אַבְּרַבַנְאֵל בפירושו הראשון<sup><a href=\"#note-2\" id=\"noteref-2\">ב</a></sup>&nbsp;לשמו של שמשון, מציע שנקרא כך על שם ייעודו לשמש את ישראל.</p>\r\n<h3 style=\"color: rgb(0, 0, 0);\">שִׁמְשׁוֹן מלשון שְׁמָמָה</h3>\r\n<p>בפירושו השני<sup><a href=\"#note-3\" id=\"noteref-3\">ג</a></sup>&nbsp;לשמו של שמשון, כותב ר\' יצחק אַבְּרַבַנְאֵל שנקרא כך לרמוז על השממה הגדולה העתידה לפלשתים, אשר שמשון נלחם בהם.</p>\r\n<hr>\r\n<h2>נזירותו</h2>\r\n<h3 style=\"color: rgb(0, 0, 0);\">הגורמים</h3>\r\n<p>בענין הסיבה להוראת ה\' על נזירות שמשון נאמרו מספר טעמים:</p>\r\n<p>א. משום<sup><a href=\"#note-4\" id=\"noteref-4\">ד</a></sup>&nbsp;שהיה גלוי לפני מי שאמר והיה העולם שיצרו של שמשון עתיד למשוך אותו ולהטעות אותו אחר הנשים, חיסן אותו על ידי הזרתו מהיין. וכדברי חז\"ל שנזירות יין מועילה לצמצום יצר העריות: \'הרואה סוטה בקלקולה יזיר עצמו מן היין\'<sup><a href=\"#note-5\" id=\"noteref-5\">ה</a></sup>.</p>\r\n<p>ב. כדי<sup><a href=\"#note-6\" id=\"noteref-6\">ו</a></sup>&nbsp;לקדש אותו ולהבדיל אותו לגדול ולהיות ההיפך מהדגם של הפשתים האוכלים מאכלים טמאים וסובאי יין. ובזאת תזרום שנאה בדמו של שמשון אשר תניעו להלחם ולנקום בם נקמת ה\'.</p>\r\n<p>ג. מאחר<sup><a href=\"#note-7\" id=\"noteref-7\">ז</a></sup>&nbsp;שמעשיו של שמשון היו לעתים תמוהים מאוד, רצה הקב\"ה למנוע את האפשרות להלעיז על שמשון שעשה מעשים אלו מתוך שכרות.</p>\r\n<p><br></p>\r\n<hr>\n<h2>הערות</h2>\n<ol style=\"list-style:none;padding:0;\">\n<li id=\"note-1\"><sup>א</sup> סוטה י. <a href=\"#noteref-1\">↩</a></li>\n<li id=\"note-2\"><sup>ב</sup> אברבנאל שופטים יג כד <a href=\"#noteref-2\">↩</a></li>\n<li id=\"note-3\"><sup>ג</sup> שם שם שם שם <a href=\"#noteref-3\">↩</a></li>\n<li id=\"note-4\"><sup>ד</sup> רלב\"ג שופטים יג ג <a href=\"#noteref-4\">↩</a></li>\n<li id=\"note-5\"><sup>ה</sup> ברכות סג.; סוטה ב. <a href=\"#noteref-5\">↩</a></li>\n<li id=\"note-6\"><sup>ו</sup> אברבנאל שופטים יג ב <a href=\"#noteref-6\">↩</a></li>\n<li id=\"note-7\"><sup>ז</sup> שם שם שם שם <a href=\"#noteref-7\">↩</a></li>\n</ol>', 'שמשון', NOW(), NOW());
INSERT INTO tanahpedia_entry (id, title, content, unique_name, created_at, updated_at) VALUES (UUID(), 'משה רבנו', '<p>מֹשֶׁה רַבֵּנוּ, מושיען של ישראל, אדון הנביאים, איש האלהים.</p>\r\n<hr>\r\n<h2>שמו</h2>\r\n<p>הכתוב אומר:</p>\r\n<p>וַיִּגְדַּ֣ל הַיֶּ֗לֶד וַתְּבִאֵ֨הוּ֙ לְבַת־פַּרְעֹ֔ה וַֽיְהִי־לָ֖הּ לְבֵ֑ן וַתִּקְרָ֤א שְׁמוֹ֙ מֹשֶׁ֔ה וַתֹּ֕אמֶר כִּ֥י מִן־הַמַּ֖יִם מְשִׁיתִֽהוּ׃<sup><a href=\"#note-1\" id=\"noteref-1\">א</a></sup></p>\r\n<h3>מי קרא את שמו מֹשֶׁה?</h3>\r\n<p>מהפסוק הנ\"ל לא כל כך ברור מי קרא למֹשֶׁה בשם זה, ובאמת יש כמה דעות במפרשים:</p>\r\n<p>א. בת פרעה<sup><a href=\"#note-2\" id=\"noteref-2\">ב</a></sup>.</p>\r\n<p>ב. אמו של משה, יוכבד<sup><a href=\"#note-3\" id=\"noteref-3\">ג</a></sup>.</p>\r\n<p>ג. השכינה<sup><a href=\"#note-4\" id=\"noteref-4\">ד</a></sup>.</p>\r\n<h3>הסכמת הקב\"ה לשם מֹשֶׁה:</h3>\r\n<p>אָמַר לוֹ הַקָּדוֹשׁ בָּרוּךְ הוּא לְמשֶׁה: חַיֶּיךָ, מִכָּל שֵׁמוֹת שֶׁנִּקְרְאוּ לְךָ אֵינִי קוֹרֵא אוֹתְךָ אֶלָּא בַּשֵּׁם שֶׁקְּרָאַתְךָ בּתְיָה בַת פַּרְעֹה<sup><a href=\"#note-5\" id=\"noteref-5\">ה</a></sup>.<br></p>\r\n<h3>למה לא נקרא משוי?</h3>\r\n<p>א. היה&nbsp;ראוי לקרות אותו משוי שנמשה מן המים, אלא קראתו משה, אמרה הוא משה את עצמו, כלומר זכותו גרמה לו להנצל<sup><a href=\"#note-6\" id=\"noteref-6\">ו</a></sup>.</p>\r\n<p>ב. דבר אחר, על&nbsp;שם ישראל שהוא משה אותם והוציאם ממצרים, שנאמר והוצא את עמי בני ישראל ממצרים, לכך נקרא שמו משה, שהוא משה אחרים<sup><a href=\"#note-7\" id=\"noteref-7\">ז</a></sup>.</p>\r\n<p>ג.&nbsp;ואל תתמה בעבור ש[שמו ]איננו משוי, כי השמות אינם נשמרים כמו הפעלים<sup><a href=\"#note-8\" id=\"noteref-8\">ח</a></sup>.</p>\r\n<hr>\r\n<h2 style=\"color: rgb(0, 0, 0);\">שמותיו הנוספים</h2>\r\n<h3 style=\"color: rgb(0, 0, 0);\">אבי</h3>\r\n<p style=\"color: rgb(0, 0, 0);\">על שהיה&nbsp;אב בתורה אב בחכמה אב בנביאות<sup><a href=\"#note-9\" id=\"noteref-9\">ט</a></sup>.</p>\r\n<h3 style=\"color: rgb(0, 0, 0);\">[אבי]גדור</h3>\r\n<p>על שגדר פרצותיהן של ישראל<sup><a href=\"#note-10\" id=\"noteref-10\">י</a></sup>.</p>\r\n<h3 style=\"color: rgb(0, 0, 0);\">[אבי]זנוח</h3>\r\n<p style=\"color: rgb(0, 0, 0);\">על שהזניח עוונותיהם של ישראל<sup><a href=\"#note-11\" id=\"noteref-11\">יא</a></sup>, ובפרט עֲבוֹדָה זָרָה<sup><a href=\"#note-12\" id=\"noteref-12\">יב</a></sup>.</p>\r\n<h3 style=\"color: rgb(0, 0, 0);\">חבר</h3>\r\n<p style=\"color: rgb(0, 0, 0);\">א. משום שחיבר את ישראל לאביהם שבשמים<sup><a href=\"#note-13\" id=\"noteref-13\">יג</a></sup>.</p>\r\n<p style=\"color: rgb(0, 0, 0);\">ב.&nbsp;שֶׁהֶעֱבִיר<sup><a href=\"#note-14\" id=\"noteref-14\">יד</a></sup>&nbsp;הַפֻּרְעָנִיּוּת מִלָּבוֹא בָּעוֹלָם<sup><a href=\"#note-15\" id=\"noteref-15\">טו</a></sup>.</p>\r\n<h3>טוב<sup><a href=\"#note-16\" id=\"noteref-16\">טז</a></sup></h3>\r\n<p>לעת תולדתו היה מציאות טוב גמור, ולא כמו שאר נבראים שאין מעלתם הטוב הגמור<sup><a href=\"#note-17\" id=\"noteref-17\">יז</a></sup>. בעל מדות טובות<sup><a href=\"#note-18\" id=\"noteref-18\">יח</a></sup>.<br></p>\r\n<h3>טוֹבִיָּ-ה<sup><a href=\"#note-19\" id=\"noteref-19\">יט</a></sup></h3>\r\n<p>היה משותף בשמו שם&nbsp;יָּ-ה כי הטוב של משה ענין אלקי<sup><a href=\"#note-20\" id=\"noteref-20\">כ</a></sup>. בעל מדות טובות, והפנה אותם לעבודת ה\'<sup><a href=\"#note-21\" id=\"noteref-21\">כא</a></sup>.</p>\r\n<h3 style=\"color: rgb(0, 0, 0);\">יקותיאל</h3>\r\n<p style=\"color: rgb(0, 0, 0);\">גרם לישראל שיקוו לא-ל<sup><a href=\"#note-22\" id=\"noteref-22\">כב</a></sup>.</p>\r\n<h3 style=\"color: rgb(0, 0, 0);\">ירד</h3>\r\n<p>א. על שם המן שירד לישראל בימיו של משה<sup><a href=\"#note-23\" id=\"noteref-23\">כג</a></sup>.</p>\r\n<p>ב. שֶׁהוֹרִיד אֶת הַשְּׁכִינָה מִלְּמַעְלָה לְמַטָּה<sup><a href=\"#note-24\" id=\"noteref-24\">כד</a></sup>.</p>\r\n<p>ג.&nbsp;שֶׁהוֹרִיד אֶת הַתּוֹרָה מִלְּמַעְלָה לְמַטָּה<sup><a href=\"#note-25\" id=\"noteref-25\">כה</a></sup>.</p>\r\n<p>ד.&nbsp;יֶרֶד - לְשׁוֹן מְלוּכָה<sup><a href=\"#note-26\" id=\"noteref-26\">כו</a></sup>.</p>\r\n<h3 style=\"color: rgb(0, 0, 0);\">מוניוס</h3>\r\n<p>ושמו בלשון מצרים היה מוניוס, וכן כתוב בספר עבודת האדמה הנעתק מלשון מצרים אל לשון קדרים, [ו]גם ככה בספרי חכמי יון. אולי למדה בת פרעה לשונינו או שאלה[ ממי שיודע עברית]<sup><a href=\"#note-27\" id=\"noteref-27\">כז</a></sup>.</p>\r\n<h3 style=\"color: rgb(0, 0, 0);\">[אבי]סוכו</h3>\r\n<p style=\"color: rgb(0, 0, 0);\">א. מפני שנעשה לישראל כסוכה<sup><a href=\"#note-28\" id=\"noteref-28\">כח</a></sup>.</p>\r\n<p style=\"color: rgb(0, 0, 0);\">ב. שֶׁהָיָה אֲבִיהֶן שֶׁל נְבִיאִים שֶׁסּוֹכִים<sup><a href=\"#note-29\" id=\"noteref-29\">כט</a></sup>&nbsp;בְּרוּחַ הַקֹּדֶשׁ ובלשון לועזית מסויימת קוראים לְנָבִיא סַכְיָא<sup><a href=\"#note-30\" id=\"noteref-30\">ל</a></sup>.</p>\r\n<h3 style=\"color: rgb(0, 0, 0);\">שְׁמַעְיָה</h3>\r\n<p>שֶׁשָּׁמַע יָ-הּ תְּפִלָּתוֹ<sup><a href=\"#note-31\" id=\"noteref-31\">לא</a></sup>.<br></p>\r\n<h3 style=\"color: rgb(0, 0, 0);\"><hr>\r\n</h3>\r\n<h2>אדון הנביאים</h2>\r\n\r\n\r\n<p><span style=\"text-decoration: underline;\">וַיְדַבֵּ֣ר מֹשֶׁ֔ה אֶל־יְ-הוָ֖ה לֵאמֹֽר</span><sup><a href=\"#note-32\" id=\"noteref-32\">לב</a></sup>&nbsp;-&nbsp;כל זמן שיחפוץ רוח הקודש לובשתו ונבואה שורה עליו, ואינו צריך לכוון דעתו ולהזדמן לה, שהרי הוא מכוון ומזומן ועומד כמלאכי השרת. לפיכך מתנבא בכל עת<sup><a href=\"#note-33\" id=\"noteref-33\">לג</a></sup>.</p>\r\n<p><span style=\"text-decoration: underline;\">כַּֽאֲשֶׁ֛ר יְדַבֵּ֥ר אִ֖ישׁ אֶל־רֵעֵ֑הוּ</span><sup><a href=\"#note-34\" id=\"noteref-34\">לד</a></sup>&nbsp;-&nbsp;כמו שאין אדם נבהל לשמוע דברי חברו, כך היה כוח בדעתו של משה רבנו להבין דברי הנבואה; והוא עומד על עומדו שלם<sup><a href=\"#note-35\" id=\"noteref-35\">לה</a></sup>.</p>\r\n<p><span style=\"text-decoration: underline;\">וּתְמֻנַ֥ת יְהוָ֖ה יַבִּ֑יט</span><sup><a href=\"#note-36\" id=\"noteref-36\">לו</a></sup>&nbsp;-&nbsp;הציור ההוא היה משיגו כולו ובבירור, כמי שרואה באספקלריא מצוחצחת ומאירה שאין עיכוב לראייתו<sup><a href=\"#note-37\" id=\"noteref-37\">לז</a></sup>.</p>\r\n<p><span style=\"text-decoration: underline;\">וּמַרְאֶה֙ וְלֹ֣א בְחִידֹ֔ת</span><sup><a href=\"#note-38\" id=\"noteref-38\">לח</a></sup>&nbsp;-&nbsp;הידיעות היו מגיעות לו בבירורם ולא על ידי חידות<sup><a href=\"#note-39\" id=\"noteref-39\">לט</a></sup>.&nbsp;</p>\r\n<p><span style=\"text-decoration: underline;\">אֲנִ֨י אַֽעֲבִ֤יר <span style=\"font-weight: bold;\">כָּל</span>־טוּבִי֙ עַל־פָּנֶ֔יךָ</span><sup><a href=\"#note-40\" id=\"noteref-40\">מ</a></sup>&nbsp;- משה זכה שיגלו לו כל סדרי הבריאה, וניתן לו רשות לחקור את הכל ולחפש הכל, ונמסרו בידו כל המפתחות שנמסרו לבן אדם מעולם<sup><a href=\"#note-41\" id=\"noteref-41\">מא</a></sup>.</p>\r\n<p>הכרה במעלת נבואתו של משה רבנו נמנית ע\"י הרמב\"ם בין י\"ג עיקרי האמונה היהודית<sup><a href=\"#note-42\" id=\"noteref-42\">מב</a></sup>.</p>\r\n<hr>\r\n<h2>איש האלהים</h2>\r\n<p>משה רבינו הוא הקדום מבין עשרת האישים המכונים \'איש האלהים\'<sup><a href=\"#note-43\" id=\"noteref-43\">מג</a></sup>.</p>\r\n<h3>כהן גדול</h3>\r\n<p>לפי דעה בחז\"ל<sup><a href=\"#note-44\" id=\"noteref-44\">מד</a></sup>&nbsp;שימש כל תקופת המדבר בכהונה גדולה, ויתפרש \'איש האלהים\' - איש מיוחד המקריב לה\'<sup><a href=\"#note-45\" id=\"noteref-45\">מה</a></sup>.</p>\r\n<h3>מתיר נדרו של הקב\"ה</h3>\r\n<p>לאחר שחטאו ישראל בעגל<sup><a href=\"#note-46\" id=\"noteref-46\">מו</a></sup>, יצא חרון אף מאת האלקים וביקש להביא רעה על שונאיהם של ישראל<sup><a href=\"#note-47\" id=\"noteref-47\">מז</a></sup>. משה התייצב לסנגר על ישראל<sup><a href=\"#note-48\" id=\"noteref-48\">מח</a></sup>&nbsp;וכביכול התיר את נדרו של אלקים<sup><a href=\"#note-49\" id=\"noteref-49\">מט</a></sup>.</p>\r\n<h3>יותר מאיש, פחות מה\' וצבאותיו</h3>\r\n<p>ביחס לכלל האנושות משה רבנו במדרגה גבוהה כאלהים, אך ביחס להקב\"ה וצבאותיו הוא עדיין איש<sup><a href=\"#note-50\" id=\"noteref-50\">נ</a></sup>.</p>\r\n<h3>נמנע מאכילה כמלאכים</h3>\r\n<p>למרות שהוא איש, בשר ודם, בעלותו לשמים הסתדר משה ללא לחם ומים<sup><a href=\"#note-51\" id=\"noteref-51\">נא</a></sup>&nbsp;כמו הרוחניים<sup><a href=\"#note-52\" id=\"noteref-52\">נב</a></sup>.</p>\r\n<h3>בגוף גשמי אך עסקיו רוחניים</h3>\r\n<p>משה האיש התקיים בתוך גוף גשמי, אך מחשבת לבו והשכלת מוחו היו עסוקים בקודש, בא-להים בלבד<sup><a href=\"#note-53\" id=\"noteref-53\">נג</a></sup>.</p>\r\n<h3>עומד על הר סיני ומשוחח עם רבונו של עולם</h3>\r\n<p>רגליו של משה עומדות בהר סיני וכולו בתוך השמים. צופה ומביט כל מה שיש בשמים, ואלקים מדבר עמו כאדם המדבר עם חברו<sup><a href=\"#note-54\" id=\"noteref-54\">נד</a></sup>.</p>\r\n<hr id=\"[object Object]\">\r\n\r\n<h2>חיבוריו<sup><a href=\"#note-55\" id=\"noteref-55\">נה</a></sup></h2>\r\n<p>כתב את התורה, ספר איוב, כמה ממזמורי תהילים.</p>\r\n\r\n<hr>\n<h2>הערות</h2>\n<ol style=\"list-style:none;padding:0;\">\n<li id=\"note-1\"><sup>א</sup> שמות ב י <a href=\"#noteref-1\">↩</a></li>\n<li id=\"note-2\"><sup>ב</sup> חזקוני שמות ב י <a href=\"#noteref-2\">↩</a></li>\n<li id=\"note-3\"><sup>ג</sup> חזקוני שמות ב י <a href=\"#noteref-3\">↩</a></li>\n<li id=\"note-4\"><sup>ד</sup> רמ\"ע מפאנו עשרה מאמרות חקור דין חלק ג פרק ד <a href=\"#noteref-4\">↩</a></li>\n<li id=\"note-5\"><sup>ה</sup> ויקרא רבה פרשה א אות ג <a href=\"#noteref-5\">↩</a></li>\n<li id=\"note-6\"><sup>ו</sup> מדרש הגדול שמות ב י <a href=\"#noteref-6\">↩</a></li>\n<li id=\"note-7\"><sup>ז</sup> שם שם שם שם; וכן כתב ספורנו שמות ב י <a href=\"#noteref-7\">↩</a></li>\n<li id=\"note-8\"><sup>ח</sup> אבן עזרא שמות ב י <a href=\"#noteref-8\">↩</a></li>\n<li id=\"note-9\"><sup>ט</sup> מגילה יג. <a href=\"#noteref-9\">↩</a></li>\n<li id=\"note-10\"><sup>י</sup> מגילה יג.; דעת ר\' הוּנָא בַּר אַחָא בויקרא רבה פרשה א אות ג <a href=\"#noteref-10\">↩</a></li>\n<li id=\"note-11\"><sup>יא</sup> מגילה יג. <a href=\"#noteref-11\">↩</a></li>\n<li id=\"note-12\"><sup>יב</sup> ויקרא רבה פרשה א אות ג <a href=\"#noteref-12\">↩</a></li>\n<li id=\"note-13\"><sup>יג</sup> מגילה יג.; ויקרא רבה פרשה א אות ג <a href=\"#noteref-13\">↩</a></li>\n<li id=\"note-14\"><sup>יד</sup> אותיות אהח\"ע מתחלפות ביניהן <a href=\"#noteref-14\">↩</a></li>\n<li id=\"note-15\"><sup>טו</sup> ויקרא רבה פרשה א אות ג <a href=\"#noteref-15\">↩</a></li>\n<li id=\"note-16\"><sup>טז</sup> ר\' מאיר בסוטה יב.; <a href=\"#noteref-16\">↩</a></li>\n<li id=\"note-17\"><sup>יז</sup> מהר\"ל בגבורות ה\' פרק י\"ז <a href=\"#noteref-17\">↩</a></li>\n<li id=\"note-18\"><sup>יח</sup> שם משמואל שמות תרע\"ו <a href=\"#noteref-18\">↩</a></li>\n<li id=\"note-19\"><sup>יט</sup> ר\' יְהוּדָה בסוטה יב.; רַבִּי יְהוּדָה בְּרַבִּי אִלְעָאי בויקרא רבה פרשה א אות ג <a href=\"#noteref-19\">↩</a></li>\n<li id=\"note-20\"><sup>כ</sup> מהר\"ל בגבורות ה\' פרק י\"ז <a href=\"#noteref-20\">↩</a></li>\n<li id=\"note-21\"><sup>כא</sup> שם משמואל שמות תרע\"ו <a href=\"#noteref-21\">↩</a></li>\n<li id=\"note-22\"><sup>כב</sup> מגילה יג. <a href=\"#noteref-22\">↩</a></li>\n<li id=\"note-23\"><sup>כג</sup> מגילה יג.; דעת ר\' לוי ור\' סימא בויקרא רבה פרשה א אות ג <a href=\"#noteref-23\">↩</a></li>\n<li id=\"note-24\"><sup>כד</sup> דעת ר\' חנינא בר פפא בויקרא רבה פרשה א אות ג <a href=\"#noteref-24\">↩</a></li>\n<li id=\"note-25\"><sup>כה</sup> דעת ר\' חנינא בר פפא בויקרא רבה פרשה א אות ג <a href=\"#noteref-25\">↩</a></li>\n<li id=\"note-26\"><sup>כו</sup> דעת ר\' סימון בר פפא בויקרא רבה פרשה א אות ג <a href=\"#noteref-26\">↩</a></li>\n<li id=\"note-27\"><sup>כז</sup> אבן עזרא שמות ב י <a href=\"#noteref-27\">↩</a></li>\n<li id=\"note-28\"><sup>כח</sup> ויקרא רבה פרשה א אות ג <a href=\"#noteref-28\">↩</a></li>\n<li id=\"note-29\"><sup>כט</sup> ויקרא רבה פרשה א אות ג <a href=\"#noteref-29\">↩</a></li>\n<li id=\"note-30\"><sup>ל</sup> מגילה יג. <a href=\"#noteref-30\">↩</a></li>\n<li id=\"note-31\"><sup>לא</sup> רַבִּי יְהוֹשֻׁעַ בַּר נְחֶמְיָה בויקרא רבה פרשה א אות ג <a href=\"#noteref-31\">↩</a></li>\n<li id=\"note-32\"><sup>לב</sup> במדבר כז טו <a href=\"#noteref-32\">↩</a></li>\n<li id=\"note-33\"><sup>לג</sup> משנה תורה הלכות יסודי התורה פרק ז הלכה יג (ו) <a href=\"#noteref-33\">↩</a></li>\n<li id=\"note-34\"><sup>לד</sup> שמות לג יא <a href=\"#noteref-34\">↩</a></li>\n<li id=\"note-35\"><sup>לה</sup> משנה תורה הלכות יסודי התורה פרק ז הלכה יב (ו) <a href=\"#noteref-35\">↩</a></li>\n<li id=\"note-36\"><sup>לו</sup> במדבר יב ח <a href=\"#noteref-36\">↩</a></li>\n<li id=\"note-37\"><sup>לז</sup> דרך ה\' חלק ג פרק ה אות ה <a href=\"#noteref-37\">↩</a></li>\n<li id=\"note-38\"><sup>לח</sup> במדבר יב ח <a href=\"#noteref-38\">↩</a></li>\n<li id=\"note-39\"><sup>לט</sup> דרך ה\' חלק ג פרק ה אות ה <a href=\"#noteref-39\">↩</a></li>\n<li id=\"note-40\"><sup>מ</sup> שמות לג יט <a href=\"#noteref-40\">↩</a></li>\n<li id=\"note-41\"><sup>מא</sup> דרך ה\' חלק ג פרק ה אות ו <a href=\"#noteref-41\">↩</a></li>\n<li id=\"note-42\"><sup>מב</sup> פירוש הרמב\"ם למשנה סנהדרין פרק י אות א באמצע <a href=\"#noteref-42\">↩</a></li>\n<li id=\"note-43\"><sup>מג</sup> ספרי דברים וזאת הברכה שמב; ויתר התשעה הם: אלקנה, שמואל, דוד,&nbsp;שְׁמַעְיָה, עדוא, אליהו, אלישע,&nbsp;מִיכָיְהוּ ואמוץ. <a href=\"#noteref-43\">↩</a></li>\n<li id=\"note-44\"><sup>מד</sup> לדעת \'יש אומרים\' זבחים קב.; שמות רבה פרשה לא פסקא א; ויקרא רבה פרשה יא פסקא ו <a href=\"#noteref-44\">↩</a></li>\n<li id=\"note-45\"><sup>מה</sup> מתנות כהונה&nbsp;שמות רבה פרשה לא פסקא א; ואמנם יצאו נגדו יתר המפרשים אך אפשר למצוא סמך לדבריו מגרסא נוספת במדרש: \'...ומשה איש האלהים&nbsp;<span style=\"font-weight: bold;\">אבל</span>&nbsp;בניו...\' המופיעה בפסיקתא רבתי (איש שלום) פיסקא יד וכן במדרש תהילים צט. <a href=\"#noteref-45\">↩</a></li>\n<li id=\"note-46\"><sup>מו</sup> שמות לב ו <a href=\"#noteref-46\">↩</a></li>\n<li id=\"note-47\"><sup>מז</sup> שם שם י <a href=\"#noteref-47\">↩</a></li>\n<li id=\"note-48\"><sup>מח</sup> שם שם יא <a href=\"#noteref-48\">↩</a></li>\n<li id=\"note-49\"><sup>מט</sup> ריש לקיש בשמות רבה פרשה מג פסקא ד <a href=\"#noteref-49\">↩</a></li>\n<li id=\"note-50\"><sup>נ</sup> דברים רבה פרשה יא פסקא ד; תנחומא וזאת הברכה א; מדרש תהילים מזמור צ <a href=\"#noteref-50\">↩</a></li>\n<li id=\"note-51\"><sup>נא</sup> שמות לד כח;&nbsp;דברים ט ט <a href=\"#noteref-51\">↩</a></li>\n<li id=\"note-52\"><sup>נב</sup> דברים רבה פרשה יא פסקא ד; תנחומא וזאת הברכה א; מדרש תהילים מזמור צ <a href=\"#noteref-52\">↩</a></li>\n<li id=\"note-53\"><sup>נג</sup> ביאור העץ יוסף והמתנות כהונה לדברים רבה פרשה יא פסקא ד <a href=\"#noteref-53\">↩</a></li>\n<li id=\"note-54\"><sup>נד</sup> דברי ר\' יהושע בן קרחה בפרקי דר\' אליעזר פרק [מא] (מ) אשר מובאים ע\"י המהרז\"ו בביאורו לדברים רבה פרשה יא פסקא ד <a href=\"#noteref-54\">↩</a></li>\n<li id=\"note-55\"><sup>נה</sup> בבא בתרא יד: <a href=\"#noteref-55\">↩</a></li>\n</ol>', 'משה-רבנו', NOW(), NOW());
